// ===============================
// Generate Dashboard Metrics
// ===============================

const commits = $input.all();

// Total Commit
const totalCommit = commits.length;

// Total Repository
const repoSet = new Set();

// Hitung commit developer
const developerCount = {};

// Hitung commit repository
const repositoryCount = {};

for (const item of commits) {

  // -----------------------
  // Developer
  // -----------------------
  const developer =
    item.json.author_name ||
    item.json.committer_name ||
    "Unknown";

  developerCount[developer] =
    (developerCount[developer] || 0) + 1;


// -----------------------
// Repository
// -----------------------

let repository =
  item.json.project_name ||
  item.json.project?.name;

if (!repository && item.json.web_url) {
 const parts = item.json.web_url.split("/");
repository = parts[4];
}

repository = repository || "Unknown Repository";

repoSet.add(repository);

repositoryCount[repository] =
  (repositoryCount[repository] || 0) + 1;

}
// ===============================
// Total Developer
// ===============================

const totalDeveloper =
Object.keys(developerCount).length;


// ===============================
// Top Developer
// ===============================

const topDeveloper =
Object.entries(developerCount)

.sort((a,b)=>b[1]-a[1])

.slice(0,5)

.map(([developer,total_commit])=>({

developer,

total_commit

}));


// ===============================
// Top Repository
// ===============================

const topRepository =
Object.entries(repositoryCount)

.sort((a,b)=>b[1]-a[1])

.slice(0,5)

.map(([repository,total_commit])=>({

repository,

total_commit

}));


// ===============================
// Return
// ===============================

return [
{
json:{

totalRepository:repoSet.size,

totalCommit,

totalDeveloper,

topDeveloper,

topRepository

}
}
];
